import osimport hashlibimport shutilfrom datetime import datetimeclass SimpleAntivirus:    def __init__(self):        # ﾄ｣魹ｽ箚｡魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ (MD5魹ｽ魹ｽﾏ｣ﾖｵ -> 魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ)        # 魹ｽ魹ｽ魹ｽ魹ｽﾊｵ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽﾐ｣魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽﾏ｣ﾖｵ        self.virus_db = {            "e99a18c428cb38d5f260853678922e03": "Eicar-Test-Virus-Simulated",            "d41d8cd98f00b204e9800998ecf8427e": "Empty-File-Virus-Simulated"        }        self.quarantine_dir = "Quarantine_Station"        if not os.path.exists(self.quarantine_dir):            os.makedirs(self.quarantine_dir)    def calculate_md5(self, file_path):        """魹ｽ魹ｽ魹ｽ魹ｽ魹ｽﾄｼ魹ｽ魹ｽ魹ｽ MD5 魹ｽ魹ｽﾏ｣ﾖｵ"""        hash_md5 = hashlib.md5()        try:            with open(file_path, "rb") as f:                for chunk in iter(lambda: f.read(4096), b""):                    hash_md5.update(chunk)            return hash_md5.hexdigest()        except Exception as e:            print(f"魹ｽﾞｷ魹ｽ魹ｽ魹ｽﾈ｡魹ｽﾄｼ魹ｽ {file_path}: {e}")            return None    def scan_file(self, file_path):        """ﾉｨ魹ｽ襍･魹ｽ魹ｽ魹ｽﾄｼ魹ｽ"""        file_hash = self.calculate_md5(file_path)        if file_hash in self.virus_db:            return {                "status": "INFECTED",                "virus_name": self.virus_db[file_hash],                "path": file_path            }        return {"status": "CLEAN", "path": file_path}    def scan_directory(self, directory):        """ﾉｨ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽﾄｿﾂｼ"""        print(f"¥n?? 魹ｽ魹ｽ魹ｽ魹ｽﾉｨ魹ｽ魹ｽﾄｿﾂｼ: {directory} ...")        infected_files = []                for root, dirs, files in os.walk(directory):            # 魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽﾖｹ魹ｽ魹ｽﾑｭ魹ｽ魹ｽ            if self.quarantine_dir in root:                continue                            for file in files:                file_path = os.path.join(root, file)                result = self.scan_file(file_path)                                if result["status"] == "INFECTED":                    print(f"?? 魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽﾐｲ: [{result['virus_name']}] 魹ｽ魹ｽ {result['path']}")                    infected_files.append(result)                return infected_files    def quarantine(self, file_path):        """魹ｽ魹ｽ魹ｽ檔｡魹ｽ魹ｽ魹ｽﾄｼ魹ｽ魹ｽ魹ｽ魹ｽﾆｶ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ"""        if not os.path.exists(file_path):            return                    filename = os.path.basename(file_path)        # 魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽﾔｷ魹ｽﾖｹ魹ｽﾙｴ魹ｽﾖｴ魹ｽﾐ｣魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽﾊｱ魹ｽ魹ｽ魹ｽ        new_name = f"{filename}_{datetime.now().strftime('%Y%m%d%H%M%S')}"        dest_path = os.path.join(self.quarantine_dir, new_name)                try:            shutil.move(file_path, dest_path)            print(f"? 魹ｽﾑｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽﾄｼ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ: {dest_path}")        except Exception as e:            print(f"? 魹ｽ魹ｽ魹ｽ魹ｽﾊｧ魹ｽ魹ｽ: {e}")    def clean(self, file_path):        """ﾖｱ魹ｽ魹ｽﾉｾ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽﾄｼ魹ｽ"""        try:            os.remove(file_path)            print(f"??? 魹ｽ魹ｽﾉｾ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽﾄｼ魹ｽ: {file_path}")        except Exception as e:            print(f"? ﾉｾ魹ｽ魹ｽﾊｧ魹ｽ魹ｽ: {e}")# --- 魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ ---if __name__ == "__main__":    av = SimpleAntivirus()        # 1. 魹ｽ魹ｽﾈ｡魹ｽﾃｻ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ    target_path = input("魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽﾒｪﾉｨ魹ｽ魹ｽ魹ｽ魹ｽﾄｼ魹ｽ魹ｽ魹ｽﾂｷ魹ｽ魹ｽ (魹ｽ魹ｽ魹ｽ魹ｽ C:¥¥Test 魹ｽ魹ｽ ./test): ").strip()        if os.path.exists(target_path):        # 2. 魹ｽ魹ｽﾊｼﾉｨ魹ｽ魹ｽ        threats = av.scan_directory(target_path)                # 3. 魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽﾐｲ        if threats:            print(f"¥n?? ﾉｨ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ {len(threats)} 魹ｽ魹ｽ魹ｽ魹ｽﾐｲ魹ｽ魹ｽ")            action = input("魹ｽ魹ｽﾑ｡魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ: [1] 魹ｽ魹ｽ魹ｽ魹ｽ (魹ｽﾆｼ魹ｽ)  [2] ﾉｾ魹ｽ魹ｽ: ")                        for threat in threats:                if action == '1':                    av.quarantine(threat['path'])                elif action == '2':                    av.clean(threat['path'])                else:                    print("魹ｽ魹ｽﾐｧ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽﾎｴ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽﾄｼ魹ｽ魹ｽ魹ｽ")        else:            print("? ﾉｨ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽﾎｴ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽﾐｲ魹ｽ魹ｽ")    else:        print("? ﾂｷ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽﾚ｣魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽﾔ｡魹ｽ")